<script setup lang="ts">
import { computed, ref } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { ArrowRight, Eye, EyeOff, LockKeyhole, ShieldCheck, Sparkles } from '@lucide/vue'
import AsyncButton from '../components/AsyncButton.vue'
import { useSessionStore } from '../stores/session'

const session=useSessionStore(), router=useRouter(), route=useRoute()
const username=ref('admin'), password=ref(''), remember=ref(true), show=ref(false), busy=ref(false), bootstrapBusy=ref(false), error=ref('')
const localSetup=computed(()=>session.setupPending&&session.localSetupAvailable)
async function submit(){if(busy.value)return;busy.value=true;error.value='';try{const state=await session.login(username.value,password.value,remember.value);await router.push(state.setup_pending?'/setup':String(route.query.redirect||'/'))}catch(e){error.value=e instanceof Error?e.message:'登录失败'}finally{busy.value=false}}
async function beginSetup(){if(bootstrapBusy.value)return;bootstrapBusy.value=true;error.value='';try{const state=await session.beginLocalSetup();await router.push(state.setup_pending?'/setup':'/')}catch(e){error.value=e instanceof Error?e.message:'无法开始初始化'}finally{bootstrapBusy.value=false}}
</script>
<template><main class="app-backdrop grid min-h-screen place-items-center p-4"><div class="grid w-full max-w-5xl overflow-hidden rounded-[2rem] border border-[var(--line)] bg-[var(--surface-solid)] shadow-2xl md:grid-cols-[1.1fr_.9fr]"><section class="relative hidden min-h-[650px] overflow-hidden bg-gradient-to-br from-rose-100 via-pink-50 to-sky-100 p-12 text-slate-800 md:block"><div class="absolute -right-20 -top-20 h-72 w-72 rounded-full bg-white/60 blur-3xl"></div><div class="relative flex h-full flex-col"><div class="flex items-center gap-3"><span class="grid h-12 w-12 place-items-center rounded-2xl bg-rose-500 text-white shadow-lg"><Sparkles/></span><strong class="text-xl">AnimateTool</strong></div><div class="my-auto"><p class="eyebrow">YOUR ANIME COMMAND CENTER</p><h1 class="mt-4 max-w-lg text-5xl font-black leading-[1.08] tracking-[-.055em]">追番、下载、整理和播放，一切都恰到好处。</h1><p class="mt-6 max-w-md text-base leading-7 text-slate-600">一处看清今日更新、订阅状态和本地媒体，让自动化安静地完成剩下的事。</p></div><div class="flex items-center gap-2 text-sm font-bold text-slate-600"><ShieldCheck :size="18"/>所有数据留在你的设备上</div></div></section><section class="p-6 sm:p-10 md:p-12"><div class="mb-10 md:hidden"><span class="mb-4 grid h-12 w-12 place-items-center rounded-2xl bg-rose-500 text-white"><Sparkles/></span><strong class="text-xl">AnimateTool</strong></div><template v-if="localSetup"><p class="eyebrow">首次启动</p><h2 class="page-title mt-2">创建你的管理员账户</h2><p class="muted mt-3 text-sm leading-6">这是本机上的全新安装。直接开始初始化并设置你自己的密码，无需查找随机生成的临时凭据。</p><div class="panel-muted mt-8 flex items-start gap-3 p-4"><span class="grid h-10 w-10 shrink-0 place-items-center rounded-xl bg-[var(--brand-soft)] text-[var(--brand)]"><LockKeyhole :size="20"/></span><div><strong class="block">仅限本机初始化</strong><p class="muted mt-1 text-xs leading-5">此入口只在首次启动且通过 localhost 直接访问时可用，完成设置后会自动关闭。</p></div></div><p v-if="error" role="alert" class="mt-5 rounded-xl bg-red-50 p-3 text-sm font-bold text-red-700 dark:bg-red-950/40 dark:text-red-300">{{ error }}</p><AsyncButton class="btn btn-primary mt-8 w-full" :loading="bootstrapBusy" loading-label="正在准备初始化…" @click="beginSetup">开始初始化<ArrowRight :size="18"/></AsyncButton></template><template v-else><p class="eyebrow">欢迎回来</p><h2 class="page-title mt-2">登录媒体库</h2><p class="muted mt-2 text-sm">使用管理员账户继续管理你的追番自动化。</p><div v-if="session.setupPending" class="panel-muted mt-6 p-4 text-sm leading-6"><strong class="block text-[var(--warning)]">首次初始化尚未完成</strong><p class="muted mt-1">请在运行软件的电脑上通过 localhost 完成初始化；为保护管理员账户，初始化完成前不允许远程访问。</p></div><form class="mt-9 space-y-5" @submit.prevent="submit"><label class="label">用户名<input v-model="username" class="field" autocomplete="username" required/></label><label class="label">密码<div class="relative"><input v-model="password" class="field pr-12" :type="show?'text':'password'" autocomplete="current-password" required autofocus/><button class="absolute right-1 top-1 grid h-10 w-10 place-items-center rounded-lg muted" type="button" @click="show=!show" :aria-label="show?'隐藏密码':'显示密码'"><EyeOff v-if="show" :size="18"/><Eye v-else :size="18"/></button></div></label><div class="flex items-center justify-between gap-3 text-sm"><label class="flex items-center gap-2 font-bold"><input v-model="remember" type="checkbox" class="h-4 w-4 accent-[var(--brand)]"/>记住我</label><RouterLink to="/recover" class="font-bold text-[var(--brand)]">本机恢复</RouterLink></div><p v-if="error" role="alert" class="rounded-xl bg-red-50 p-3 text-sm font-bold text-red-700 dark:bg-red-950/40 dark:text-red-300">{{ error }}</p><AsyncButton type="submit" class="btn btn-primary w-full" :loading="busy" loading-label="正在登录…">进入 AnimateTool<ArrowRight :size="18"/></AsyncButton></form></template></section></div></main></template>
